def floyd_warshall(n, edges):
    """
    n     : number of vertices (0..n-1)
    edges : list of (u, v, w)
    Returns dist[i][j] = shortest path from i to j (inf if unreachable).
    """
    INF = float('inf')
    dist = [[INF] * n for _ in range(n)]
    for i in range(n):
        dist[i][i] = 0
    for u, v, w in edges:
        dist[u][v] = min(dist[u][v], w)

    for k in range(n):          # intermediate vertex
        for i in range(n):
